const items = [];
const config = $input.first().json;
const sites = config.sites || [];

for (const url of sites) {
  items.push({
    json: {
      url,
      niche: config.niche,
      credibilityRules: config.credibilityRules,
      deliveryChannels: config.deliveryChannels,
      searchSettings: config.searchSettings,
      breakingNewsAlerts: config.breakingNewsAlerts
    }
  });
}
return items;

const xmlString = $input.first().json.data || $input.first().text;
// Parse simple XML items using regex for maximum compatibility without extra node modules
const items = [];
const matches = xmlString.matchAll(/<item>([\s\S]*?)<\/item>/g);
const limitDate = new Date();
limitDate.setHours(limitDate.getHours() - 24); // Last 24 hours

for (const match of matches) {
  const content = match[1];
  const titleMatch = content.match(/<title><!\[CDATA\[([\s\S]*?)\]\]><\/title>/) || content.match(/<title>([\s\S]*?)<\/title>/);
  const linkMatch = content.match(/<link><!\[CDATA\[([\s\S]*?)\]\]><\/link>/) || content.match(/<link>([\s\S]*?)<\/link>/);
  const descMatch = content.match(/<description><!\[CDATA\[([\s\S]*?)\]\]><\/description>/) || content.match(/<description>([\s\S]*?)<\/description>/);
  const pubDateMatch = content.match(/<pubDate>([\s\S]*?)<\/pubDate>/);

  const title = titleMatch ? titleMatch[1].trim() : 'Untitled';
  const link = linkMatch ? linkMatch[1].trim() : '';
  const description = descMatch ? descMatch[1].trim().replace(/<[^>]*>/g, '') : '';
  const pubDateStr = pubDateMatch ? pubDateMatch[1].trim() : '';
  const pubDate = pubDateStr ? new Date(pubDateStr) : new Date();

  if (pubDate >= limitDate) {
    const siteUrl = $node["Split into Site Items"].json.url || "";
    const hostMatch = siteUrl.match(/:\/\/(www\.)?([^\/]+)/);
    const source = hostMatch ? hostMatch[2] : "Unknown";

    items.push({
      json: {
        title,
        link,
        description,
        pubDate: pubDate.toISOString(),
        niche: $node["Split into Site Items"].json.niche,
        credibilityRules: $node["Split into Site Items"].json.credibilityRules,
        deliveryChannels: $node["Split into Site Items"].json.deliveryChannels,
        searchSettings: $node["Split into Site Items"].json.searchSettings,
        breakingNewsAlerts: $node["Split into Site Items"].json.breakingNewsAlerts,
        source: source
      }
    });
  }
}
return items.slice(0, 5); // Limit to top 5 articles per feed to avoid API limits

const html = $input.first().json.data || $input.first().text || "";
const matches = [];

// Regex to extract search results from DuckDuckGo HTML
const resultRegex = /<div class="result[^"]*">([\s\S]*?)<\/div>/g;
const resultMatches = html.matchAll(resultRegex);

for (const match of resultMatches) {
  const block = match[1];
  const titleMatch = block.match(/<a class="result__url"[^>]*>([\s\S]*?)<\/a>/);
  const snippetMatch = block.match(/<a class="result__snippet"[^>]*>([\s\S]*?)<\/a>/);

  if (titleMatch && snippetMatch) {
    matches.push({
      title: titleMatch[1].replace(/<[^>]*>/g, '').trim(),
      snippet: snippetMatch[1].replace(/<[^>]*>/g, '').trim()
    });
  }
}

const searchResults = matches.slice(0, 3).map((item, idx) => `[${idx+1}] Title: ${item.title}\nSnippet: ${item.snippet}`).join('\n\n');
const originalItem = $node["Parse XML RSS Feed"].json;

return {
  json: {
    ...originalItem,
    searchResultsText: searchResults || "No external references found."
  }
};

